        [Fact]
        public void Test_EncodingCjkCharacters()
        {
            // CJK (Chinese, Japanese, Korean) characters are preserved
            var result = HtmlToMarkdownConverter.Convert("<p>中文内容</p><p>日本語テキスト</p><p>한국어 텍스트</p>", new ConversionOptions());
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("中文内容", result.Content.ToString().ToLower());
    Assert.Contains("日本語テキスト", result.Content.ToString().ToLower());
    Assert.Contains("한국어 텍스트", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_EncodingHtmlEntities()
        {
            // Common HTML entities are decoded in output
            var result = HtmlToMarkdownConverter.Convert("<p>&amp; &lt; &gt; &nbsp; &quot; &apos;</p>", new ConversionOptions());
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("&", result.Content.ToString().ToLower());
    Assert.Contains("<", result.Content.ToString().ToLower());
    Assert.Contains(">", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_EncodingNamedEntities()
        {
            // Named HTML entities like &mdash; and &hellip; are decoded
            var result = HtmlToMarkdownConverter.Convert("<p>Em dash&mdash;used for parenthetical remarks&mdash;is common. Ellipsis&hellip; indicates omission. Non-breaking&nbsp;space.</p>", new ConversionOptions());
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("—", result.Content.ToString().ToLower());
    Assert.Contains("…", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_EncodingNumericEntities()
        {
            // Numeric HTML entities (decimal and hex) are decoded
            var result = HtmlToMarkdownConverter.Convert("<p>Copyright: &#169; Trade: &#174; Euro: &#8364; Hex: &#x00A9;</p>", new ConversionOptions());
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("©", result.Content.ToString().ToLower());
    Assert.Contains("®", result.Content.ToString().ToLower());
    Assert.Contains("€", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_EncodingUnicodeEmoji()
        {
            // Emoji and Unicode characters are preserved
            var result = HtmlToMarkdownConverter.Convert("<p>Hello 🌍 World 🚀</p><p>Stars: ⭐ ✨</p>", new ConversionOptions());
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("🌍", result.Content.ToString().ToLower());
    Assert.Contains("🚀", result.Content.ToString().ToLower());
    Assert.Contains("⭐", result.Content.ToString().ToLower());

        }

        [Fact]
