        [Fact]
        public void Test_MalformedBogusCommentTripleDash()
        {
            // HTML comment ending with ---> (three dashes) must not drop content that follows (issue #339)
            var result = HtmlToMarkdownConverter.Convert("<h1>One</h1>\n<!-- /// --->\n<p>Two</p>", new ConversionOptions());
    Assert.Contains("one", result.Content.ToString().ToLower());
    Assert.Contains("two", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_MalformedDeeplyNestedElements()
        {
            // Deeply nested elements (100 levels) are handled without stack overflow
            var result = HtmlToMarkdownConverter.Convert("<div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><p>Deeply nested content</p></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div>", new ConversionOptions());
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("deeply nested content", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_MalformedMissingBlockClosingTags()
        {
            // Missing closing tags on block elements are auto-closed by parser
            var result = HtmlToMarkdownConverter.Convert("<div><h1>Title<p>First paragraph<p>Second paragraph</div>", new ConversionOptions());
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("title", result.Content.ToString().ToLower());
    Assert.Contains("first paragraph", result.Content.ToString().ToLower());
    Assert.Contains("second paragraph", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_MalformedOverlappingTags()
        {
            // Overlapping bold/italic tags are recovered by the HTML parser without panic
            var result = HtmlToMarkdownConverter.Convert("<p><b><i>bold and italic</b></i></p>", new ConversionOptions());
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("bold and italic", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_MalformedUnclosedParagraph()
        {
            // Unclosed <p> tag is recovered gracefully and content is preserved
            var result = HtmlToMarkdownConverter.Convert("<p>This paragraph is never closed", new ConversionOptions());
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("this paragraph is never closed", result.Content.ToString().ToLower());

        }

