        [Fact]
        public void Test_XssOnclickHandlerRemoved()
        {
            // onclick and other on* event handlers are removed from elements
            var result = HtmlToMarkdownConverter.Convert("<p><a href=\"https://example.com\" onclick=\"alert('xss')\">Click me</a></p><button onmouseover=\"steal_data()\">Hover me</button>", new ConversionOptions());
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("click me", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_XssScriptTagStripped()
        {
            // Script tag content is stripped and does not appear in output
            var result = HtmlToMarkdownConverter.Convert("<p>Safe content.</p><script>alert('xss')</script><p>More safe content.</p>", new ConversionOptions());
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("safe content", result.Content.ToString().ToLower());
    Assert.Contains("more safe content", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_XssSvgNestedScriptStripped()
        {
            // Script tags nested inside SVG are stripped
            var result = HtmlToMarkdownConverter.Convert("<p>Before SVG.</p><svg xmlns=\"http://www.w3.org/2000/svg\"><script>alert('svg-xss')</script><text>SVG text</text></svg><p>After SVG.</p>", new ConversionOptions());
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("before svg", result.Content.ToString().ToLower());
    Assert.Contains("after svg", result.Content.ToString().ToLower());

        }


